import tensorflow as tfimport matplotlib.pyplot as pltmnist = tf.keras.datasets.mnist(train_x, train_y), (test_x, test_y) = mnist.load_data()x_train = train_x.reshape(60000, 784).astype('float32') / 255x_test = test_x.reshape(10000, 784).astype('float32') / 255print(x_train.shape)model = tf.keras.models.Sequential([    tf.keras.layers.Dense(128, activation='relu'),    tf.keras.layers.Dense(64, activation='relu'),    tf.keras.layers.Dense(32, activation='relu'),    tf.keras.layers.Dense(10, activation='softmax')])model.compile(optimizer='sgd',              loss='sparse_categorical_crossentropy',              metrics=['accuracy'])model.fit(x_train, train_y, batch_size=64, epochs=1, validation_data=(x_test, test_y), validation_freq=1)model.summary()model.save('./model/model.h5')del model'''加载模型，识别测试集中的手写数字'''plt.imshow(test_x[3], cmap='gray')plt.show()new_model = tf.keras.models.load_model('./model/model.h5', compile=False)predict = new_model.predict(x_test)[3]print(tf.argmax(predict))